  `fee` decimal(15,2) NOT NULL,
  `amount` decimal(15,2) NOT NULL,
  `current_balance` decimal(15,2) NOT NULL DEFAULT '0.00',
  `currency` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
